from flask import Flask, render_template, request
import json

app = Flask(__name__)

@app.route('/recipe')
def showManxRecipe():
    '''
    Get recipe name from request,
    check if it’s in our list of Manx favourites,
    then show the full recipe wi’ a bonny template
    '''
    recipes = {
        'soddag': 'Boil up fine bacon, add potatoes an’ onions, simmer till rich.',
        'queenies': 'Clean scallops well, fry in butter wi’ a pinch o’ salt.',
        'bonag': 'Mix oatmeal, sugar, an’ currants, bake till golden.'
    }
    recipe_name = request.args.get('name', '')
    if recipe_name in recipes:
        return render_template('recipe.html', recipe=recipes[recipe_name])
    return 'Recipe not found, my friend.', 404

