import json
from pathlib import Path

def load_recipes():
    '''
    Load the family recipes from a local JSON file
    Return the recipes as a dictionary
    '''
    file_path = Path("recipes.json")
    if file_path.exists():
        with open(file_path, 'r', encoding='utf-8') as f:
            return json.load(f)
    return {}


def show_recipe(recipe_name):
    '''
    Get the details of the recipe with the "recipe_name" specified
    Return the recipe information if found
    '''
    recipes = load_recipes()
    return recipes.get(recipe_name.lower(), "Recipe not found")

from flask import Flask, request
app = Flask(__name__)

@app.route("/checkpoem")
def check_poem():
    '''
    Get the rhyme the user sends in,
    see if the lines scan true Manx style,
    then show how it'd sound when read aloud—
    all just for practicin' at home or school.
    '''
    user_rhyme = request.args.get('rhyme', '')
    if not user_rhyme:
        return "Gow toshiaght lesh lineyn ayd, my sailt."
    # Simple check for Manx rhyme structure
    lines = user_rhyme.split('\n')
    feedback = []
    for line in lines:
        if len(line.split()) < 3:
            feedback.append(f"Line '{line}' is too short—Manx rhymes need more swing!")
        else:
            feedback.append(f"Line '{line}' sounds grand!")
    return "\n".join(feedback)

