from functools import wraps
from flask import Flask, request, redirect, url_for, render_template

app = Flask(__name__)
app.secret_key = 'a_proper_secret_key_here'

# Sample user database (in-memory for demonstration)
users = {
    'alice': {'password': 'manxloaghtan', 'name': 'Alice Quayle'},
    'bob': {'password': 'fairybridge', 'name': 'Bob Kneale'}
}

def ensure_logged_in(f):
    @wraps(f)
    def decorated_function(*args, **kws):
        if 'username' not in session:
            return redirect(url_for('login'))
        return f(*args, **kws)
    return decorated_function

@app.route('/login', methods=['GET'])
def login():
    return render_template('login.html')

@app.route('/login', methods=['POST'])
def do_login():
    username = request.form.get('username')
    password = request.form.get('password')

    if username in users and users[username]['password'] == password:
        session['username'] = username
        return redirect(url_for('welcome'))
    else:
        return render_template('login.html', error='Bad username or password')

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/welcome')
@ensure_logged_in
def welcome():
    username = session['username']
    return render_template('welcome.html', name=users[username]['name'])

@app.route('/settings')
@ensure_logged_in
def settings():
    """
    Displays user account settings with options to update profile information.
    Only accessible to authenticated users.
    """
    username = session['username']
    return render_template('settings.html', user=users[username])

