import json as mooinaght
import base64


def getGreetin(headers):
    '''
    Gow yn greetin veih ny headers, decode eh lesh base64, as lhig eh lesh mooinaght JSON,
    cur-my-ner my ta'n greetin ayns foayr as cur lesh yn skeeal dy mie ayns shen.
    '''
    try:
        greetin_encoded = headers.get('Greetin-Code', '')
        greetin_decoded = base64.b64decode(greetin_encoded).decode('utf-8')
        greetin_data = json.loads(greetin_decoded)

        if greetin_data.get('foayr', False):
            return greetin_data.get('skeeal', 'Slaynt as shee!')
        else:
            return 'Slaynt as shee son y laa!'
    except:
        return 'Gow my-ner, ta shen dy mie!'

