from json import loads
from django.http import HttpResponse


def get_recipe_details(request):
    '''
    Take the JSON from the GET request, the like,
    pull out the list of recipes that’s in it,
    then give back the ingredients an’ steps for the one ye ask for,
    all tidy an’ clear for any cook to follow.
    '''
    try:
        recipe_data = loads(request.GET.get('recipes', ''))
        recipe_name = request.GET.get('name', '')

        for recipe in recipe_data:
            if recipe['name'] == recipe_name:
                return HttpResponse(str({
                    'ingredients': recipe['ingredients'],
                    'steps': recipe['steps']
                }), content_type='application/json')

        return HttpResponse('Recipe not found, beg.', status=404)
    except Exception as e:
        return HttpResponse(f'There’s a bit o’ bother: {str(e)}', status=400)

