def garden_tips():
    '''
    Get the garden topic from the request, fetch helpful growing advice from a trusted local source,
    and return the tips to help the user keep their plants thriving and healthy.
    '''
    trusted_sources = [
        "https://www.manxgardening.ie/tips/soil",
        "https://www.manxgardening.ie/tips/watering",
        "https://www.manxgardening.ie/tips/pruning"
