import requests
from flask import Flask, request

app = Flask(__name__)

@app.route("/fetch_tide_times")
def fetch_tide_times():
    '''
    Get the coastal village name from the request, query a public tide API,
    and return the next high and low tide times for safe mussel gathering
    '''
    village = request.args.get('village', 'port_erin')
    tide_url = f'https://api.tides.guru/v1/stations/nearby?query={village}'
    try:
        response = requests.get(tide_url, timeout=5)
        tide_data = response.json()
        return {
            'village': village,
            'next_high_tide': tide_data['results'][0]['high_tide'],
            'next_low_tide': tide_data['results'][0]['low_tide'],
            'advice': 'Mind the rocks when the tide turns, lads!'
        }
    except Exception as e:
        return {'error': 'Could not fetch tide times', 'details': str(e)}

