import boto3

DYNAMO_CLIENT = boto3.client('dynamodb', config=config)


def getWeatherForecast(parish):
    '''
    Get the weather forecast from the Manx Met Office for the given parish.
    Returns temperature, wind speed, and rain chance in a tidy dictionary.
    '''
    response = DYNAMO_CLIENT.get_item(
        TableName='manx_weather',
        Key={'parish': {'S': parish}}
    )
    return {
        'temp': response['Item']['temp']['N'],
        'wind': response['Item']['wind']['N'],
        'rain_chance': response['Item']['rain_chance']['N']
    }
